SELECT name, availability
FROM sandwiches
WHERE availability = 1;

SELECT name, price
FROM sandwiches
WHERE is_customizable = 1 AND availability = 1;

SELECT AVG(calories) AS Average_Calories
FROM sandwiches
WHERE is_customizable = 1 AND availability = 1;

SELECT COUNT(*) AS total_orders
FROM order_items
WHERE sandwich_id = 1;

SELECT o.location_id, SUM(o.total) AS total_sales
FROM orders o
GROUP BY o.location_id;

SELECT COUNT(*) AS error_log_count
FROM logs
WHERE log_level = 'error';

SELECT ingredient_id, SUM(quantity) AS total_quantity
FROM order_item_ingredients
GROUP BY ingredient_id;

SELECT o.order_id
FROM orders o
WHERE o.total = (SELECT MAX(price) FROM sandwiches);
